  END
  CLASS
	NAME "Anomalía de pp (%)"
    EXPRESSION ([pixel] = -999)
    COLOR -1 -1 -1
  END
  CLASS
	NAME "-13.8 - -13.0"
    EXPRESSION ([pixel] >= -13.8 AND [pixel] < -13.0)
