    COLOR 80 196 51
  END
  CLASS
	NAME "-11.0 - -10.5"
    EXPRESSION ([pixel] >= -11.0 AND [pixel] < -10.5)
    COLOR 25 230 168
  END
  CLASS
	NAME "-10.5 - -10.0"
    EXPRESSION ([pixel] >= -10.5 AND [pixel] < -10.0)
    COLOR 0 168 132
  END
  CLASS
	NAME "-10.0 - -5.9"
